  require(['vs/editor/editor.main'], function(monaco) {

    // Función principal que procesa todos los bloques de código
    const codeBlocks = document.querySelectorAll('pre > code');
    codeBlocks.forEach((codeBlock) => {
      const lang = getCodeLanguage(codeBlock);  // Obtener el lenguaje del bloque
      const code = codeBlock.textContent;

      // Crear el contenedor principal para el código y el botón
      const containerDiv = document.createElement('div');
      containerDiv.classList.add('code-block-container'); // Asignar una clase al contenedor

      // Crear el contenedor para Monaco
      const editorDiv = createEditorContainer(codeBlock); 

      // Crear el botón de copiar
      const copyButton = createCopyButton();

      // Agregar el botón y el editor al contenedor
      containerDiv.appendChild(copyButton);  // Añadir el botón primero
      containerDiv.appendChild(editorDiv);   // Añadir el editor después

      // Reemplazar el bloque original con el contenedor
      codeBlock.parentElement.replaceWith(containerDiv);

      // Crear el editor y ajustar su alto dinámicamente
      const editor = setupMonacoEditor(monaco, editorDiv, code, lang);
      adjustEditorHeight(editor, editorDiv);  // Ajustar la altura basado en el contenido
      

      // Asignar evento de copiar al botón
      copyButton.addEventListener('click', () => copyToClipboard(editor));
    });

    // Funciones existentes...

    function setupMonacoEditor(monaco, editorDiv, code, lang) {
      monaco.editor.defineTheme('default', {
        base: 'vs',
        inherit: true,
        rules: [
          { token: 'comment', foreground: '808080' },
          { token: 'tag', foreground: '6a15d6' },
          { token: 'attribute', foreground: '6a15d6' },
        ],
        colors: {
          'editor.background': '#FAF9FF',
        }
      });

      monaco.editor.setTheme('default');

      return monaco.editor.create(editorDiv, {
        value: code,
        language: lang,
        readOnly: true,
        automaticLayout: true,
        minimap: { enabled: false },
        scrollbar: {
          vertical: 'hidden',
          horizontal: 'hidden',
          handleMouseWheel: false
        },
        smoothScrolling: false,
        overviewRulerLanes: 0,
        renderLineHighlight: 'none',
        folding: false,
        renderIndentGuides: false,
        scrollBeyondLastLine: false
      });
    }

    function createEditorContainer(codeBlock) {
      const editorDiv = document.createElement('div');
      editorDiv.classList.add('monaco-container');
      return editorDiv;
    }

    function getCodeLanguage(codeBlock) {
      return codeBlock.className.replace('language-', '') || 'javascript';
    }

    function adjustEditorHeight(editor, editorDiv) {
      const lineHeight = editor.getOption(monaco.editor.EditorOption.lineHeight);
      const lineCount = editor.getModel().getLineCount();
      editorDiv.style.height = lineHeight * lineCount + "px";
    }

    function createCopyButton() {
      const button = document.createElement('button');
      button.innerHTML = '<svg width="18" height="18" viewBox="0 0 18 18" fill="none" xmlns="http://www.w3.org/2000/svg"><path d="M6.75 6.75V4.65C6.75 3.81 6.75 3.39 6.9135 3.069C7.0575 2.78625 7.28625 2.5575 7.569 2.4135C7.89 2.25 8.31 2.25 9.15 2.25H13.35C14.19 2.25 14.61 2.25 14.931 2.4135C15.2132 2.55731 15.4427 2.78677 15.5865 3.069C15.75 3.39 15.75 3.81 15.75 4.65V8.85C15.75 9.69 15.75 10.11 15.5865 10.431C15.4427 10.7132 15.2132 10.9427 14.931 11.0865C14.61 11.25 14.19 11.25 13.3522 11.25H11.25M6.75 6.75H4.65C3.81 6.75 3.39 6.75 3.069 6.9135C2.78677 7.05731 2.55731 7.28677 2.4135 7.569C2.25 7.89 2.25 8.31 2.25 9.15V13.35C2.25 14.19 2.25 14.61 2.4135 14.931C2.55731 15.2132 2.78677 15.4427 3.069 15.5865C3.38925 15.75 3.80925 15.75 4.64775 15.75H8.853C9.69075 15.75 10.11 15.75 10.431 15.5865C10.7132 15.4427 10.9427 15.2132 11.0865 14.931C11.25 14.61 11.25 14.1907 11.25 13.3522V11.25M6.75 6.75H8.85C9.69 6.75 10.11 6.75 10.431 6.9135C10.7132 7.05731 10.9427 7.28677 11.0865 7.569C11.25 7.88925 11.25 8.30925 11.25 9.14775V11.25" stroke="#A881FF" stroke-width="1.3" stroke-linecap="round" stroke-linejoin="round"/></svg>';
      button.classList.add('copy-button');
      return button;
    }

    function copyToClipboard(editor) {
      const code = editor.getValue();
      const textarea = document.createElement('textarea');
      textarea.value = code;
      document.body.appendChild(textarea);
      textarea.select();
      document.execCommand('copy');
      document.body.removeChild(textarea);
    }
  });

    // Función para obtener el texto del
function getTextDocument() {
    let textToRead = '';
    const markdownContent = document.querySelector('#markdown-content');
    if (!markdownContent) return "";

    markdownContent.childNodes.forEach((node, index) => {
        // Verifica si el nodo no es un .code-block-container ni un pre
        if (node.nodeType === Node.ELEMENT_NODE
            && !node.classList.contains('code-block-container')
            && node.tagName.toLowerCase() !== 'pre') {
            // Añadir el texto de nodos elementales que no sean bloques de código
            textToRead += node.textContent.trim() + ' ';
        } else if (node.nodeType === Node.TEXT_NODE) {
            // Añadir texto directo (nodos de texto puros)
            textToRead += node.textContent.trim() + ' ';
        }
    });
    return textToRead.trim();
}

  window.speechSynthesis.onvoiceschanged = function() {
        // SAM Model
        const model = {
            isPlaying: false,
            synth: window.speechSynthesis,
            utterance: new SpeechSynthesisUtterance(getTextDocument()),
            voices: [],
        };

        // Configuración inicial
        model.voices = model.synth.getVoices();
        model.utterance.voice = model.voices[7];
        model.utterance.lang = model.utterance.voice.lang;
        model.utterance.rate = 1;
        model.utterance.pitch = 1;

        // SAM Actions
        const actions = {
            toggleSpeech: () => {
                if (model.isPlaying) {
                    actions.stopSpeech();
                } else {
                    actions.playSpeech();
                }
            },
            playSpeech: () => {
                model.synth.cancel();
                model.synth.speak(model.utterance);
                model.synth.cancel();
                model.synth.speak(model.utterance);
                model.isPlaying = true;
                render();
            },
            stopSpeech: () => {
                model.synth.cancel();
                model.isPlaying = false;
                render();
            }
        };

        // SAM State
        function render() {
            const speakButton = document.getElementById("voiceButton");
            speakButton.innerHTML = model.isPlaying ? '${Qgt}' : '${A9e}';
        }

        // Event listeners
        document.getElementById("voiceButton").addEventListener("click", actions.toggleSpeech);
        
        // Listener para cuando termine la reproducción
        model.utterance.onend = () => {
            model.isPlaying = false;
            render();
        };

        // Inicializar
        render();
};

